import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';
import WordCloud from './WordCloud';

const StatisticsPage = () => {
  const [stats, setStats] = useState({ proposals: 0, signatures: 0, users: 0 });

  useEffect(() => {
    const fetchStats = async () => {
      const { count: proposals } = await supabase.from('proposals').select('*', { count: 'exact', head: true });
      const { count: users } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
      setStats({ proposals: proposals || 0, signatures: 0, users: users || 0 });
    };
    fetchStats();
  }, []);

  const trends = [
    { name: 'Élections', count: 52 },
    { name: 'Gouvernance', count: 45 },
    { name: 'Justice', count: 38 },
    { name: 'Décentralisation', count: 29 },
  ];

  return (
    <div className="stats-page">
      <div className="stats-header">
        <h1>Tableau de bord analytique</h1>
        <p>Analyse sémantique des contributions citoyennes</p>
      </div>
      <div className="stats-cards">
        <div className="stat-card"><div className="stat-num">{stats.proposals}</div><div>Propositions</div></div>
        <div className="stat-card"><div className="stat-num">{stats.users}</div><div>Citoyens actifs</div></div>
        <div className="stat-card"><div className="stat-num">{stats.signatures}</div><div>Signatures</div></div>
      </div>
      <div className="trends-section">
        <h3>Thèmes tendances</h3>
        {trends.map(t => (
          <div key={t.name} className="trend-bar">
            <span>{t.name}</span>
            <div className="bar"><div className="bar-fill" style={{ width: `${(t.count / 52) * 100}%` }}></div></div>
            <span>{t.count}</span>
          </div>
        ))}
      </div>
      <WordCloud />
    </div>
  );
};

export default StatisticsPage;
